const std = @import("std");

pub fn parse(bytes: []const u8) !void {
    var parser = std.json.Parser.init(std.testing.allocator, false);
    defer parser.deinit();
    _ = try parser.parse(bytes);
}

const std = @import("std");

const Schema = struct { name: []const u8 };

pub fn parse(allocator: std.mem.Allocator, bytes: []const u8) !Schema {
    const parsed = try std.json.parseFromSlice(Schema, allocator, bytes, .{});
    defer parsed.deinit();
    return parsed.value;
}
